import React, { useState } from 'react';
import { View, Text, Button } from 'react-native';
import PaymentModule from './PaymentModule';

const App = () => {
  const [paymentData, setPaymentData] = useState(null);

  const handleMakePurchase = async () => {
    try {
      const paymentResponse = await PaymentModule.makePurchase();
      setPaymentData(paymentResponse);
    } catch (error) {
      console.log('Error making purchase:', error);
    }
  };

  return (
    <View>
      <Text>In-App Purchases and Digital Wallet Transactions</Text>
      <Button title="Make Purchase" onPress={handleMakePurchase} />
      {paymentData && (
        <Text>Payment Data: {JSON.stringify(paymentData)}</Text>
      )}
    </View>
  );
};